raw_output:
{
  "experiment_plan": {
    "what_to_compare": "米国の8年生・10年生・12年生について、2012年以前と2012年以降の年次反復横断データを比較する。加えて、年次レベルでのスクリーン活動（特に電子コミュニケーション・ソーシャルメディア）と非スクリーン活動（対面交流・スポーツ・宿題・宗教活動）、および経済指標（失業率）との関連を比較する。",
    "what_to_measure": "主要アウトカムは心理的well-being複合指標（自尊感情、生活満足度、領域満足度、幸福感）。説明変数はスクリーン活動頻度、活動タイプ別利用（電子コミュニケーション、ソーシャルメディア、ゲーム、一般インターネット）、非スクリーン活動頻度、年次失業率。補助的に、年次トレンド、学年別トレンド、Granger因果方向、用量反応関係を測定する。",
    "procedure": "1) Monitoring the Futureの1991-2016年反復横断データを用いる。2) 2012年を境にwell-beingの平均水準と傾きを比較する。3) 活動タイプ別にwell-beingとの横断相関を推定する。4) 年次集計データでスクリーン活動、非スクリーン活動、失業率、well-beingの時系列関係を推定し、Granger因果分析を行う。5) スクリーン活動の種類別・利用文脈別に層別化し、総スクリーンタイムのみのモデルと比較する。6) 失業率を含むモデル、活動タイプを含むモデル、両者を同時に含むモデルを比較し、説明力の増分を評価する。7) 事前に定めた判定規則に従い、各仮説をaccept/reject/holdで判定する。",
    "identification_assumptions": [
      {
        "id": "IA1",
        "description": "2012年以降の変化を捉える比較において、主要な制度変更や測定変更がwell-being指標の急変を直接生じていないこと。",
        "if_violated": "2012年前後の差が実際の心理変化ではなく測定アーティファクトである可能性が高まり、時点比較による因果解釈は保留する。"
      },
      {
        "id": "IA2",
        "description": "年次集計レベルでのGranger分析において、十分な時系列長と定常性、または適切な差分化・トレンド調整により、先行関係が推定可能であること。",
        "if_violated": "先行性の推定が不安定になり、方向性に関する判定はholdとする。"
      },
      {
        "id": "IA3",
        "description": "自己報告によるスクリーン活動・非スクリーン活動・well-being測定の誤差が、年次間比較や群間比較を系統的に歪めないこと。",
        "if_violated": "相関の減衰や偽の差が生じうるため、効果の有無は保留し、感度分析を優先する。"
      },
      {
        "id": "IA4",
        "description": "失業率は青少年well-beingに対する経済環境の妥当な代理変数であり、少なくとも主要なマクロ経済変動を代表していること。",
        "if_violated": "経済要因仮説の検証力が低下するため、H2の判定はholdとする。"
      },
      {
        "id": "IA5",
        "description": "活動タイプ別の自己報告は、電子コミュニケーション、ゲーム、対面交流、スポーツ等を十分に区別できること。",
        "if_violated": "H4の活動タイプ差の判定が不可能または不安定となり、holdとする。"
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
        "accept_if": "2012年以降にwell-beingが有意に低下し、その低下がスクリーン活動増加の大きい年・学年でより大きく、電子コミュニケーションが非スクリーン活動より強い負の関連を示し、かつ電子コミュニケーション→well-beingのGranger先行が支持される。",
        "reject_if": "2012年以降にスクリーン活動が増加していてもwell-being低下がスクリーン活動の多い群で一貫せず、電子コミュニケーションの増加がwell-being低下に先行せず、活動とwell-beingの関連が年次トレンド・Granger分析で支持されない。",
        "hold_if": "2012年以降の低下は確認されるが、スクリーン活動との関連が弱い、方向性が不明確、または活動タイプ差が不十分で、主因とまでは判定できない。"
      },
      {
        "id": "H2",
        "accept_if": "失業率などの経済指標がwell-beingと強く連動し、経済指標を統制するとスクリーン活動とwell-beingの関連が大きく減衰し、経済指標→well-beingの時系列先行がスクリーン活動→well-beingより強い。",
        "reject_if": "経済指標を考慮してもwell-being低下が十分に説明されず、スクリーン活動の増加がwell-being低下に独立して関連し、かつスクリーン活動の時系列先行が経済指標より強い。",
        "hold_if": "経済指標とスクリーン活動の双方が関連するが、どちらが主因かを判定するには効果量・先行性・頑健性が不足している。"
      },
      {
        "id": "H3",
        "accept_if": "Granger分析で電子コミュニケーション→well-beingとwell-being→電子コミュニケーションの両方向が有意であり、低well-being群で後続年のスクリーン活動増加が大きく、スクリーン活動増加群で後続年のwell-being低下も大きい。",
        "reject_if": "スクリーン活動からwell-beingへの一方向のみ、またはwell-beingからスクリーン活動への逆方向のみが示され、双方向の時系列的予測が支持されない。",
        "hold_if": "一方向の先行は示されるが、逆方向の証拠が弱い、または年次データの分解能不足で双方向性を確定できない。"
      },
      {
        "id": "H4",
        "accept_if": "ソーシャルメディアやテキストなどの電子コミュニケーションがゲームや一般インターネット利用より強く負に関連し、対面交流・スポーツ・宿題・宗教活動が正に関連し、総スクリーンタイムより活動タイプ別モデルの説明力が明確に高い。",
        "reject_if": "スクリーン活動の種類や利用文脈を区別しても効果差がなく、どのスクリーン活動も同程度にwell-beingと関連し、非スクリーン活動の保護効果も見られない。",
        "hold_if": "活動タイプ差は示唆されるが、測定誤差やカテゴリ間の重なりのため、総スクリーンタイムを超える説明力改善が十分に確認できない。"
      }
    ],
    "analysis_forks": [
      "2012年を閾値とする二分比較 vs 年次連続トレンド回帰",
      "個人レベルの横断相関 vs 年次集計レベルの時系列相関",
      "総スクリーンタイムモデル vs 活動タイプ別モデル",
      "スクリーン活動のみのモデル vs 失業率のみのモデル vs 両者同時モデル",
      "電子コミュニケーション中心の分析 vs ソーシャルメディア中心の分析 vs ゲーム中心の分析",
      "Granger因果の方向性検証（スクリーン活動→well-being / well-being→スクリーン活動）",
      "学年別層別分析（8年生・10年生・12年生）",
      "非スクリーン活動を保護因子として扱うモデル vs 代替行動として扱うモデル"
    ]
  }
}
